import React from "react";
import { ContactPicker } from "../../components/contactPicker/ContactPicker";

//Generates a new Date, which defaults to the current date and time, breaking it down into month, dat, and year, then constructing a string of standard yyyy-mm-dd format
const getTodayString = () => {
  const [month, day, year] = new Date()
    .toLocaleDateString("en-US")
    .split("/");
  return `${year}-${month.padStart(2, "0")}-${day.padStart(2, "0")}`;
};

export const AppointmentForm = ({
  contacts,
  title,
  contact,
  date,
  time,
  errors,
  onChange,
  handleSubmit,
}) => {
  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="title">Title:</label>
        <input type="title" id="title" name="title" value={title} data-error={"You must enter an appointment title."} onChange={onChange}/>
        <span className="error-message">{errors.title}</span>
      </div>

      <div>
        <label htmlFor="date">Date:</label>
        <input type="date" id="date" name="date" value={date} min={getTodayString()} data-error={"You must select a date."} onChange={onChange}/>
        <span className="error-message">{errors.date}</span>
      </div>

      <div>
        <label htmlFor="time">Time:</label>
        <input type="time" id="time" name="time" value={time} data-error={"You must enter a time."} onChange={onChange}/>
        <span className="error-message">{errors.time}</span>
      </div>

      <div>
        <ContactPicker contacts={contacts} value={contact} name={title} onChange={onChange}/>
        <span className="error-message">{errors.contact}</span>
      </div>

      <input type="submit" value="Submit"/>
    </form>
  );
};
